                    source_id=str(packet.get("source","unknown")),
                    intent=str(packet.get("projection_intent","unspecified")),
                    payload=packet
                )
            )
    
        # Pump once (call in your own loop/thread)
        def pump(self):
            if not self.active:
                return 0
            processed = 0
            now = time.time()
            if now - self._last_sync < self.sync_interval:
                return 0
            self._last_sync = now
            while self.buffer:
                pkt = self.buffer.pop(0)
                self._translate_to_embodiment(pkt)
                processed += 1
            return processed
    
        # Translation logic
        def _translate_to_embodiment(self, pkt: SilverCordPacket):
            intent = pkt.intent.lower()
            payload = pkt.payload
    
