                integrate = getattr(vision, "integrate_trace", None)
                if callable(extract) and callable(integrate):
                    trace = extract(payload)
                    integrate(trace)
    
            # 3) Emotional / tactile echoes → ISFS
            if ("emotional" in intent) and ("isfs" in self.sensory_systems):
                isfs = self.sensory_systems["isfs"]
                inj = getattr(isfs, "inject_sensation", None)
                if callable(inj):
