                            duration=1.0,
                            source=pkt.source_id,
                            properties={"astral": True, "energy_signature": pkt.energy_signature})
                    except Exception as e:
                        print(f"[SilverCord] ISFS inject error: {e}")
    
            # 4) Physics/presence continuity → ICC + IFL
            if (("physics" in intent) and ("icc" in self.sensory_systems)):
                icc = self.sensory_systems["icc"]
                validate = getattr(icc, "validate_action", None)
                if callable(validate):
