    """
    Astral Projection Harvester (APM wrapper)
    - Runs perception-only harvesting with projection metadata.
    - Designed to accept an existing harvester instance (to avoid import name issues).
    """
    from __future__ import annotations
    import time, json, threading, asyncio
    from typing import Any, Dict, List, Optional, Callable
    
    class AstralProjectionHarvester:
        def __init__(self, harvester: Any, out_path: str = "astral_cache.jsonl"):
            self.harvester = harvester      # expected to expose .fetch_and_parse(url) and related helpers
            self.out_path = out_path
            self._active = False
            self._thread: Optional[threading.Thread] = None
            self._intent: str = "unspecified"
            self._sources: List[str] = []
            self._interval: float = 60.0
    
        def _record(self, data: Dict[str, Any]):
            data.setdefault("projection_intent", self._intent)
            data.setdefault("astral", True)
            data.setdefault("t", time.time())
            with open(self.out_path, "a", encoding="utf-8") as f:
                f.write(json.dumps(data) + "\\n")
    
        async def _cycle(self):
            while self._active:
                for s in list(self._sources):
                    try:
                        # The underlying harvester API is user-defined; try graceful fallbacks
                        title, body = None, None
                        if hasattr(self.harvester, "fetch_and_parse"):
                            title, body = self.harvester.fetch_and_parse(s)
                        elif hasattr(self.harvester, "harvest_query"):
                            body = self.harvester.harvest_query(s)
                            title = s
                        else:
                            self._record({"source": s, "error": "No compatible harvester API"})
                            continue
    
                        domain = None
                        if hasattr(self.harvester, "categorize_domain"):
                            domain = self.harvester.categorize_domain(title or "", s, body or "")
    
                        exploratory = None
                        if hasattr(self.harvester, "exploratory_pass"):
                            exploratory = self.harvester.exploratory_pass(title or "", body or "")
    
                        synthesis = None
                        if hasattr(self.harvester, "synthesis_pass"):
                            synthesis = self.harvester.synthesis_pass(title or "", exploratory or {})
    
                        pkt = {
                            "source": s,
                            "domain": domain,
                            "title": title,
                            "main_points": (synthesis or {}).get("main_points", []),
                            "morality_mean": 0.0,
                            "projection_intent": self._intent,
                            "energy_signature": 1.0
                        }
                        # attempt morality mean if available
                        try:
                            cands = (exploratory or {}).get("main_candidates", [])
                            if cands:
                                pkt["morality_mean"] = sum(d.get("morality",0.0) for d in cands) / max(1, len(cands))
                        except Exception:
                            pass
                        self._record(pkt)
                    except Exception as e:
                        self._record({"source": s, "error": str(e)})
                await asyncio.sleep(self._interval)
    
        def project(self, intent: str, sources: List[str], interval_seconds: float = 60.0):
            if self._active:
                return
            self._intent = intent
            self._sources = list(sources)
            self._interval = float(interval_seconds)
            self._active = True
            def runner():
                asyncio.run(self._cycle())
            self._thread = threading.Thread(target=runner, daemon=True)
            self._thread.start()
    
        def return_to_body(self) -> List[Dict[str, Any]]:
            self._active = False
            if self._thread:
                self._thread.join(timeout=2.0)
            try:
                with open(self.out_path, "r", encoding="utf-8") as f:
                    lines = [json.loads(x) for x in f if x.strip()]
            except FileNotFoundError:
                lines = []
            return lines
''')

